/**
 * Figma auto-names new layers after the tool that created them: `Rectangle 12`,
 * `Frame 5`, `Ellipse 6`, `Group 3`. These names carry no design intent — the
 * serialized line already states the node `[TYPE]` and its `#id`, so the name is
 * pure context-budget noise.
 *
 * The trailing ` \d+` is REQUIRED, not optional: a bare word like `Line`, `Star`,
 * `Group`, or `Section` is just as likely to be a deliberate designer-given name,
 * and stripping it would lose real signal. Only the unmistakable `Word 123` form
 * is auto-generated. (Mirrors framelink-app's design-parser AUTO_GENERATED_NAME_PATTERN.)
 */
const AUTO_GENERATED_NAME =
  /^(?:Frame|Rectangle|Ellipse|Line|Vector|Group|Component|Instance|Polygon|Star|Text|Image|Slice|Section|Boolean|Union|Subtract|Intersect|Exclude|Arrow)\s+\d+$/;

export function isAutoGeneratedName(name: string): boolean {
  return AUTO_GENERATED_NAME.test(name);
}

/**
 * True when a node's `name` adds no signal over the rest of its serialized line
 * and should be dropped. Shared by all output formats so tree/yaml/json stay
 * consistent.
 *
 * TEXT layers are dropped wholesale: Figma auto-names them after their content,
 * so the name is nearly always a duplicate of — or, worse, a stale copy left
 * behind after the content was edited — the `text` value we already emit. A stale
 * name actively misleads the LLM consumer, so it's never worth keeping.
 */
export function isNoiseName(name: string, type: string | undefined): boolean {
  return type === "TEXT" || isAutoGeneratedName(name);
}
